// @ts-nocheck
import React from 'react';
import { useQuery, useMutation } from '@tanstack/react-query';
import { api } from '../../lib/api';
import { notifyError } from '../../lib/notify';
import * as Icons from '../../icons';
import { Modal as _Component3 } from '../../components/ui/Modal';

export function UpdateModal({ onClose }: { onClose: () => void }) {
  const [log, setLog] = React.useState<string[]>([]);
  const [running, setRunning] = React.useState(false);
  const [done, setDone] = React.useState(false);
  const logRef = React.useRef<HTMLTextAreaElement>(null);

  const { data: versionInfo, isFetching: checking, refetch } = useQuery({
    queryKey: ['system-version'],
    queryFn: () => api.systemVersion(),
    retry: false,
  });

  React.useEffect(() => {
    if (logRef.current) {
      logRef.current.scrollTop = logRef.current.scrollHeight;
    }
  }, [log]);

  async function runUpdate() {
    setLog([]);
    setRunning(true);
    setDone(false);
    try {
      await api.systemUpdate((event: any) => {
        if (event.type === 'log' || event.type === 'error' || event.type === 'done') {
          const prefix = event.type === 'error' ? '✗ ' : event.type === 'done' ? '✓ ' : '  ';
          setLog(prev => [...prev, prefix + (event.message ?? '')]);
          if (event.type === 'done') setDone(true);
        }
      });
    } catch (e: any) {
      notifyError(e);
      setLog(prev => [...prev, '✗ ' + (e?.message ?? 'Unknown error')]);
    } finally {
      setRunning(false);
    }
  }

  const upToDate = versionInfo?.upToDate;
  const behindBy = versionInfo?.behindBy ?? 0;

  return (
    <_Component3 title="System Update" onClose={onClose} width="max-w-2xl">
      <div className="space-y-4 text-xs">
        {/* Version info */}
        <div className="grid grid-cols-2 gap-3 border border-nv-border rounded p-3 bg-nv-toolbar/50">
          <div>
            <span className="text-nv-textSubtle block mb-0.5">Current Version</span>
            <span className="font-mono font-semibold">{versionInfo?.current ?? '…'}</span>
          </div>
          <div>
            <span className="text-nv-textSubtle block mb-0.5">Latest (remote)</span>
            <span className="font-mono font-semibold">{versionInfo?.latest ?? '…'}</span>
          </div>
          <div>
            <span className="text-nv-textSubtle block mb-0.5">Local commit</span>
            <span className="font-mono text-2xs text-nv-textMuted">{versionInfo?.commit ?? '…'}</span>
          </div>
          <div>
            <span className="text-nv-textSubtle block mb-0.5">Remote commit</span>
            <span className="font-mono text-2xs text-nv-textMuted">{versionInfo?.remoteCommit ?? '…'}</span>
          </div>
        </div>

        {/* Status badge */}
        {!checking && versionInfo && (
          <div className={`flex items-center gap-2 text-xs px-3 py-1.5 rounded border ${
            upToDate
              ? 'bg-green-50 border-green-200 text-green-700'
              : 'bg-yellow-50 border-yellow-200 text-yellow-700'
          }`}>
            {upToDate
              ? <><Icons._Component4 size={12} /> Up to date</>
              : <><Icons.MF size={12} /> {behindBy} commit{behindBy !== 1 ? 's' : ''} behind remote — update available</>
            }
            <button onClick={() => refetch()} className="ml-auto nv-btn" disabled={checking}>
              {checking ? <Icons.Pe size={11} className="animate-spin" /> : <Icons.Yn size={11} />}
            </button>
          </div>
        )}

        {/* Log output */}
        {log.length > 0 && (
          <div>
            <div className="text-2xs text-nv-textSubtle mb-1">Update log</div>
            <textarea
              ref={logRef}
              readOnly
              className="w-full h-40 nv-input font-mono text-2xs bg-nv-bg"
              value={log.join('\n')}
            />
          </div>
        )}

        {done && (
          <div className="text-xs text-green-600 font-semibold">
            Update complete. Please reload the page and restart the server if running as a Node.js process.
          </div>
        )}
      </div>

      <div className="flex justify-end gap-2 mt-4">
        <button className="nv-btn" onClick={onClose} disabled={running}>Close</button>
        <button
          className="nv-btn-primary"
          onClick={runUpdate}
          disabled={running || upToDate || checking}
        >
          {running ? <><Icons.Pe size={11} className="animate-spin inline mr-1" />Updating…</> : 'Pull & Update'}
        </button>
      </div>
    </_Component3>
  );
}
