import { create } from 'zustand';

export const useContextMenuStore = create(e => ({
  open: false,
  x: 0,
  y: 0,
  items: [],
  show: (t, n) => {
    t.preventDefault();
    e({
      open: true,
      x: t.clientX,
      y: t.clientY,
      items: n
    });
  },
  hide: () => e({
    open: false
  })
}));
