import React from "react";
import { useSnippetStore, Snippet } from "./snippetStore";

interface Props {
  onClose: () => void;
  onInsert?: (body: string) => void;
}

const emptyForm = { prefix: "", body: "", description: "" };

export function SnippetManager({ onClose, onInsert }: Props) {
  const { snippets, addSnippet, updateSnippet, deleteSnippet } = useSnippetStore();
  const [editing, setEditing] = React.useState<Snippet | null>(null);
  const [form, setForm] = React.useState(emptyForm);
  const [isNew, setIsNew] = React.useState(false);

  const openNew = () => {
    setIsNew(true);
    setEditing(null);
    setForm(emptyForm);
  };

  const openEdit = (s: Snippet) => {
    setIsNew(false);
    setEditing(s);
    setForm({ prefix: s.prefix, body: s.body, description: s.description ?? "" });
  };

  const handleSave = () => {
    if (!form.prefix.trim() || !form.body.trim()) return;
    if (isNew) {
      addSnippet({ prefix: form.prefix.trim(), body: form.body, description: form.description });
    } else if (editing) {
      updateSnippet(editing.id, { prefix: form.prefix.trim(), body: form.body, description: form.description });
    }
    setEditing(null);
    setIsNew(false);
    setForm(emptyForm);
  };

  const handleCancel = () => {
    setEditing(null);
    setIsNew(false);
    setForm(emptyForm);
  };

  const showForm = isNew || editing !== null;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50" onClick={onClose}>
      <div className="bg-nv-panel border border-nv-border rounded-lg shadow-xl w-[620px] max-h-[80vh] flex flex-col" onClick={e => e.stopPropagation()}>
        <div className="flex items-center justify-between px-4 py-3 border-b border-nv-border">
          <span className="font-semibold text-sm">SQL Snippets</span>
          <button className="nv-btn !py-0.5 !px-1.5" onClick={onClose}>✕</button>
        </div>

        <div className="flex flex-1 min-h-0">
          {/* List */}
          <div className="w-[55%] border-r border-nv-border flex flex-col min-h-0">
            <div className="px-3 py-2 border-b border-nv-border">
              <button className="nv-btn-primary text-xs !py-1" onClick={openNew}>+ New Snippet</button>
            </div>
            <div className="overflow-y-auto flex-1">
              {snippets.length === 0 && (
                <div className="p-4 text-xs text-nv-textMuted">No snippets yet.</div>
              )}
              {snippets.map(s => (
                <div key={s.id} className={`flex items-start gap-2 px-3 py-2 border-b border-nv-borderLight hover:bg-nv-hover cursor-pointer ${editing?.id === s.id ? "bg-nv-selected/20" : ""}`} onClick={() => openEdit(s)}>
                  <div className="flex-1 min-w-0">
                    <div className="flex items-center gap-2">
                      <code className="text-xs font-mono text-nv-accent font-semibold">{s.prefix}</code>
                      {s.description && <span className="text-2xs text-nv-textSubtle truncate">{s.description}</span>}
                    </div>
                    <div className="text-2xs font-mono text-nv-textMuted mt-0.5 truncate">{s.body}</div>
                  </div>
                  <div className="flex items-center gap-1 shrink-0">
                    {onInsert && (
                      <button className="nv-btn !py-0.5 !px-1.5 text-2xs" title="Insert into editor" onClick={e => { e.stopPropagation(); onInsert(s.body); onClose(); }}>Insert</button>
                    )}
                    <button className="nv-btn !py-0.5 !px-1.5 text-2xs text-nv-danger" title="Delete" onClick={e => { e.stopPropagation(); deleteSnippet(s.id); if (editing?.id === s.id) handleCancel(); }}>✕</button>
                  </div>
                </div>
              ))}
            </div>
          </div>

          {/* Editor */}
          <div className="flex-1 flex flex-col min-h-0 p-3 gap-2">
            {showForm ? (
              <>
                <div className="text-xs font-semibold text-nv-textSubtle mb-1">{isNew ? "New Snippet" : "Edit Snippet"}</div>
                <div>
                  <label className="text-2xs text-nv-textMuted block mb-1">Prefix (trigger)</label>
                  <input className="nv-input w-full font-mono" value={form.prefix} placeholder="e.g. ssf" onChange={e => setForm(f => ({ ...f, prefix: e.target.value }))} />
                </div>
                <div className="flex-1 flex flex-col min-h-0">
                  <label className="text-2xs text-nv-textMuted block mb-1">Body (SQL)</label>
                  <textarea className="nv-input w-full flex-1 resize-none font-mono text-xs" rows={5} value={form.body} placeholder="SELECT * FROM " onChange={e => setForm(f => ({ ...f, body: e.target.value }))} />
                </div>
                <div>
                  <label className="text-2xs text-nv-textMuted block mb-1">Description (optional)</label>
                  <input className="nv-input w-full" value={form.description} placeholder="Short description" onChange={e => setForm(f => ({ ...f, description: e.target.value }))} />
                </div>
                <div className="flex gap-2 pt-1">
                  <button className="nv-btn-primary text-xs" onClick={handleSave} disabled={!form.prefix.trim() || !form.body.trim()}>Save</button>
                  <button className="nv-btn text-xs" onClick={handleCancel}>Cancel</button>
                </div>
              </>
            ) : (
              <div className="flex-1 flex items-center justify-center text-xs text-nv-textMuted">
                Select a snippet to edit, or create a new one.<br />
                <span className="text-2xs mt-1 block text-center">Type a prefix in the SQL editor and press <kbd className="px-1 border border-nv-border rounded">Tab</kbd> to expand.</span>
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}
