// @ts-nocheck
import React from 'react';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { api } from '../../lib/api';
import { notifyError, confirm } from '../../lib/notify';
import * as Icons from '../../icons';

function formatTs(ts: string) {
  try {
    return new Date(ts).toLocaleString(undefined, { dateStyle: 'short', timeStyle: 'medium' });
  } catch { return ts; }
}

export function AuditLogPanel() {
  const qc = useQueryClient();
  const [page, setPage] = React.useState(1);
  const [actionFilter, setActionFilter] = React.useState('');
  const [targetFilter, setTargetFilter] = React.useState('');
  const limit = 50;

  const { data, isFetching, refetch } = useQuery({
    queryKey: ['audit-log', page, actionFilter, targetFilter],
    queryFn: () => api.auditLog({ page, limit, action: actionFilter || undefined, target: targetFilter || undefined }),
    retry: false,
    keepPreviousData: true,
  });

  const purgeMutation = useMutation({
    mutationFn: (days: number) => api.purgeAuditLog(days),
    onSuccess: (res: any) => {
      qc.invalidateQueries({ queryKey: ['audit-log'] });
      setPage(1);
    },
    onError: notifyError,
  });

  async function handlePurge() {
    if (await confirm('Delete all audit events older than 90 days?', 'Purge Audit Log')) {
      purgeMutation.mutate(90);
    }
  }

  const events: any[] = (data as any)?.events ?? [];
  const total: number = (data as any)?.total ?? 0;
  const pages: number = (data as any)?.pages ?? 1;

  return (
    <div className="h-full flex flex-col bg-nv-panel">
      {/* Toolbar */}
      <div className="flex items-center gap-2 px-2 py-1.5 bg-nv-toolbar border-b border-nv-border shrink-0">
        <Icons._Component0 size={12} className="text-nv-textSubtle" />
        <span className="font-semibold text-xs">Audit Log</span>
        <input
          value={actionFilter}
          onChange={e => { setActionFilter(e.target.value); setPage(1); }}
          placeholder="Filter action…"
          className="nv-input text-xs w-32"
        />
        <input
          value={targetFilter}
          onChange={e => { setTargetFilter(e.target.value); setPage(1); }}
          placeholder="Filter target…"
          className="nv-input text-xs w-32"
        />
        <span className="text-xs text-nv-textMuted ml-2">{total} events</span>
        <button className="nv-btn ml-auto" onClick={() => refetch()} disabled={isFetching} title="Refresh">
          {isFetching ? <Icons.Pe size={11} className="animate-spin" /> : <Icons.Yn size={11} />}
        </button>
        <button className="nv-btn text-red-500" onClick={handlePurge} disabled={purgeMutation.isPending} title="Purge old events">
          <Icons._Component38 size={11} /> Purge old
        </button>
      </div>

      {/* Table */}
      <div className="flex-1 overflow-auto">
        <table className="w-full text-xs">
          <thead className="sticky top-0 bg-nv-gridHeader border-b border-nv-border z-10">
            <tr>
              <th className="text-left px-2 py-1.5 font-semibold w-36">Time</th>
              <th className="text-left px-2 py-1.5 font-semibold w-36">User</th>
              <th className="text-left px-2 py-1.5 font-semibold w-36">Action</th>
              <th className="text-left px-2 py-1.5 font-semibold">Target</th>
              <th className="text-left px-2 py-1.5 font-semibold w-56">Payload</th>
            </tr>
          </thead>
          <tbody>
            {events.length === 0 && !isFetching && (
              <tr>
                <td colSpan={5} className="text-center py-8 text-nv-textMuted">No audit events.</td>
              </tr>
            )}
            {events.map((e: any) => (
              <tr key={e.id} className="border-b border-nv-borderLight hover:bg-nv-hover">
                <td className="px-2 py-1 text-nv-textMuted text-2xs">{formatTs(e.createdAt)}</td>
                <td className="px-2 py-1 truncate max-w-0">{e.email ?? e.userId ?? '—'}</td>
                <td className="px-2 py-1 font-mono text-nv-accent">{e.action}</td>
                <td className="px-2 py-1 truncate">{e.target ?? ''}</td>
                <td className="px-2 py-1 font-mono text-2xs text-nv-textMuted truncate" title={JSON.stringify(e.payload)}>
                  {e.payload && Object.keys(e.payload).length > 0
                    ? JSON.stringify(e.payload).slice(0, 60)
                    : ''
                  }
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {/* Pagination */}
      {pages > 1 && (
        <div className="flex items-center gap-2 px-3 py-1.5 border-t border-nv-border bg-nv-toolbar shrink-0 text-xs">
          <button
            className="nv-btn"
            onClick={() => setPage(p => Math.max(1, p - 1))}
            disabled={page <= 1}
          >
            &larr; Prev
          </button>
          <span>Page {page} / {pages}</span>
          <button
            className="nv-btn"
            onClick={() => setPage(p => Math.min(pages, p + 1))}
            disabled={page >= pages}
          >
            Next &rarr;
          </button>
        </div>
      )}
    </div>
  );
}
