import { create } from "zustand";
import { persist } from "zustand/middleware";

export interface Snippet {
  id: string;
  prefix: string;
  body: string;
  description?: string;
}

interface SnippetStore {
  snippets: Snippet[];
  addSnippet: (s: Omit<Snippet, "id">) => void;
  updateSnippet: (id: string, patch: Partial<Omit<Snippet, "id">>) => void;
  deleteSnippet: (id: string) => void;
}

const DEFAULTS: Snippet[] = [
  { id: "ssf", prefix: "ssf", body: "SELECT * FROM ", description: "Select all from table" },
  { id: "scount", prefix: "scount", body: "SELECT COUNT(*) FROM ", description: "Count rows" },
  { id: "sl1", prefix: "sl1", body: "SELECT * FROM  LIMIT 1", description: "Select first row" },
  { id: "dw", prefix: "dw", body: "DELETE FROM  WHERE ", description: "Delete with WHERE" },
  { id: "uw", prefix: "uw", body: "UPDATE  SET  WHERE ", description: "Update with WHERE" },
];

export const useSnippetStore = create<SnippetStore>()(
  persist(
    (set) => ({
      snippets: DEFAULTS,
      addSnippet: (s) =>
        set((st) => ({
          snippets: [
            ...st.snippets,
            { ...s, id: crypto.randomUUID ? crypto.randomUUID() : String(Date.now()) },
          ],
        })),
      updateSnippet: (id, patch) =>
        set((st) => ({
          snippets: st.snippets.map((s) => (s.id === id ? { ...s, ...patch } : s)),
        })),
      deleteSnippet: (id) =>
        set((st) => ({ snippets: st.snippets.filter((s) => s.id !== id) })),
    }),
    { name: "nv-snippets" }
  )
);
