/* recovered from production bundle — store/theme */
// @ts-nocheck

import { create } from 'zustand';
import { getThemePreference, applyTheme } from '../lib/auth';

export const useThemeStore = create((e, t) => ({
  theme: getThemePreference(),
  setTheme: n => {
    applyTheme(n);
    e({
      theme: n
    });
  },
  toggle: () => {
    const n = t().theme === "light" ? "dark" : "light";
    applyTheme(n);
    e({
      theme: n
    });
  }
}));
if (typeof window !== "undefined") {
  applyTheme(getThemePreference());
}
