// @ts-nocheck
import React from 'react';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { api } from '../../lib/api';
import { notifyError } from '../../lib/notify';
import * as Icons from '../../icons';
import { Modal } from '../../components/ui/Modal';

const ROLES = ['viewer', 'editor', 'dba'] as const;
type GrantRole = typeof ROLES[number];

export function AccessManager({ connectionId, connectionName, onClose }: {
  connectionId: string;
  connectionName: string;
  onClose: () => void;
}) {
  const qc = useQueryClient();
  const [newUserId, setNewUserId] = React.useState('');
  const [newRole, setNewRole] = React.useState<GrantRole>('viewer');

  const { data: grantsData, isFetching } = useQuery({
    queryKey: ['connection-grants', connectionId],
    queryFn: () => api.connectionGrants(connectionId),
    retry: false,
  });

  const { data: usersData } = useQuery({
    queryKey: ['users'],
    queryFn: () => api.users(),
    retry: false,
  });

  const grants: any[] = (grantsData as any)?.grants ?? [];
  const users: any[] = (usersData as any)?.users ?? [];
  const grantedUserIds = new Set(grants.map((g: any) => g.userId));
  const availableUsers = users.filter((u: any) => !grantedUserIds.has(u.id) && u.role !== 'admin');

  const upsertMutation = useMutation({
    mutationFn: ({ userId, role }: { userId: string; role: string }) =>
      api.upsertConnectionGrant(connectionId, userId, role),
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: ['connection-grants', connectionId] });
      setNewUserId('');
      setNewRole('viewer');
    },
    onError: notifyError,
  });

  const revokeMutation = useMutation({
    mutationFn: (userId: string) => api.deleteConnectionGrant(connectionId, userId),
    onSuccess: () => qc.invalidateQueries({ queryKey: ['connection-grants', connectionId] }),
    onError: notifyError,
  });

  function handleAdd() {
    if (!newUserId) return;
    upsertMutation.mutate({ userId: newUserId, role: newRole });
  }

  return (
    <Modal title={`Access Manager — ${connectionName}`} onClose={onClose} width="max-w-xl">
      <div className="space-y-4 text-xs">
        {/* Add grant */}
        <div className="border border-nv-border rounded p-3 bg-nv-toolbar/50 space-y-2">
          <div className="font-semibold text-nv-textSubtle">Grant access to user</div>
          <div className="flex gap-2 items-end">
            <div className="flex-1">
              <label className="text-2xs text-nv-textSubtle block mb-0.5">User</label>
              <select
                className="nv-select w-full"
                value={newUserId}
                onChange={e => setNewUserId(e.target.value)}
              >
                <option value="">— select user —</option>
                {availableUsers.map((u: any) => (
                  <option key={u.id} value={u.id}>{u.email} ({u.role})</option>
                ))}
              </select>
            </div>
            <div className="w-28">
              <label className="text-2xs text-nv-textSubtle block mb-0.5">Role</label>
              <select
                className="nv-select w-full"
                value={newRole}
                onChange={e => setNewRole(e.target.value as GrantRole)}
              >
                {ROLES.map(r => <option key={r} value={r}>{r}</option>)}
              </select>
            </div>
            <button
              className="nv-btn-primary"
              onClick={handleAdd}
              disabled={!newUserId || upsertMutation.isPending}
            >
              {upsertMutation.isPending
                ? <Icons.Pe size={11} className="animate-spin" />
                : <Icons._Component5 size={11} />
              }
              Grant
            </button>
          </div>
        </div>

        {/* Existing grants */}
        <div>
          <div className="flex items-center gap-2 mb-2">
            <span className="font-semibold">Active grants</span>
            {isFetching && <Icons.Pe size={11} className="animate-spin text-nv-textMuted" />}
          </div>
          {grants.length === 0 ? (
            <p className="text-nv-textMuted text-2xs py-4 text-center">
              No grants yet. Users with the <em>admin</em> system role always have full access.
            </p>
          ) : (
            <table className="w-full text-xs">
              <thead className="bg-nv-gridHeader border-b border-nv-border">
                <tr>
                  <th className="text-left px-2 py-1.5 font-semibold">Email</th>
                  <th className="text-left px-2 py-1.5 font-semibold w-20">System Role</th>
                  <th className="text-left px-2 py-1.5 font-semibold w-24">Grant Role</th>
                  <th className="px-2 py-1.5 w-20"></th>
                </tr>
              </thead>
              <tbody>
                {grants.map((g: any) => (
                  <tr key={g.userId} className="border-b border-nv-borderLight hover:bg-nv-hover">
                    <td className="px-2 py-1.5">{g.email ?? g.userId}</td>
                    <td className="px-2 py-1.5 text-nv-textMuted">{g.userRole ?? '—'}</td>
                    <td className="px-2 py-1.5">
                      <select
                        className="nv-select py-0"
                        value={g.role}
                        onChange={e => upsertMutation.mutate({ userId: g.userId, role: e.target.value })}
                      >
                        {ROLES.map(r => <option key={r} value={r}>{r}</option>)}
                      </select>
                    </td>
                    <td className="px-2 py-1.5 text-center">
                      <button
                        className="nv-btn text-red-500"
                        onClick={() => revokeMutation.mutate(g.userId)}
                        disabled={revokeMutation.isPending}
                        title="Revoke"
                      >
                        <Icons._Component2 size={11} />
                      </button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          )}
        </div>
      </div>
      <div className="flex justify-end mt-4">
        <button className="nv-btn" onClick={onClose}>Close</button>
      </div>
    </Modal>
  );
}
